.darma-loader-darma-research-meteor-shower-bars { --speed: var(--loader-speed, 1s); --accent: var(--loader-color, #38bdf8); --accent-2: var(--loader-secondary-color, #6366f1); width: calc(var(--loader-size, 86px) * 1.4); height: var(--loader-size, 86px); display: flex; align-items: flex-end; justify-content: center; gap: 7%; transform: skewX(-8deg); }
.darma-loader-darma-research-meteor-shower-bars span { width: 9%; height: 30%; border-radius: 999px 999px 4px 4px; background: linear-gradient(180deg, #fff, var(--accent), var(--accent-2)); box-shadow: 0 0 14px var(--accent); animation: darma-loader-darma-research-meteor-shower-bars-meteor-bar calc(var(--speed) * 1.05) ease-in-out infinite; }
.darma-loader-darma-research-meteor-shower-bars span:nth-child(2) { animation-delay: .1s; } .darma-loader-darma-research-meteor-shower-bars span:nth-child(3) { animation-delay: .2s; } .darma-loader-darma-research-meteor-shower-bars span:nth-child(4) { animation-delay: .3s; } .darma-loader-darma-research-meteor-shower-bars span:nth-child(5) { animation-delay: .4s; } .darma-loader-darma-research-meteor-shower-bars span:nth-child(6) { animation-delay: .5s; }
@keyframes darma-loader-darma-research-meteor-shower-bars-meteor-bar { 0%,100% { height: 24%; filter: brightness(.7); } 45% { height: 96%; filter: brightness(1.3); transform: translateY(-7px); } }

